parameters.value:
=You are a SOC analyst. Classify this security alert. Return ONLY valid JSON with no markdown:
{"severity": "CRITICAL|HIGH|MEDIUM|LOW", "confidence": "HIGH|MEDIUM|LOW", "action": "one-sentence recommended action"}

When uncertain between severities, choose the HIGHER one. CRITICAL: active attack. HIGH: likely malicious. MEDIUM: suspicious. LOW: benign.

ALERT: {{ $json.body.title }}. {{ $json.body.description }}
HOST: {{ $json.body.host }}

parameters.jsCode:
// Parse the Ollama response and extract severity
const raw = $input.item.json.response || '';
let parsed = {};
try {
  // Strip code fences if present
  const clean = raw.replace(/```json?/g, '').replace(/```/g, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {
  // Parse failed — default to HIGH for safe failure
  parsed = {
    severity: 'HIGH',
    confidence: 'LOW',
    action: 'MANUAL REVIEW — AI output could not be parsed.',
    parse_error: e.message,
    raw_output: raw
  };
}

// Pass through the original alert data too
return {
  json: {
    alert: $('Alert Webhook').item.json.body,
    classification: parsed,
    ai_raw: raw
  }
};

// AUTO-ESCALATE: CRITICAL alerts — no approval needed
const alert = $json.alert;
const classification = $json.classification;
const logEntry = {
  timestamp: new Date().toISOString(),
  alert_id: alert.id || 'unknown',
  host: alert.host,
  title: alert.title,
  severity: classification.severity,
  confidence: classification.confidence,
  action_taken: 'AUTO_ESCALATED',
  ai_action: classification.action,
  approver: null,
  notes: 'CRITICAL alert auto-escalated without human approval per policy.'
};
console.log('AUDIT:', JSON.stringify(logEntry));
return { json: logEntry };

// APPROVAL REQUIRED: HIGH alerts
const alert = $json.alert;
const classification = $json.classification;
const logEntry = {
  timestamp: new Date().toISOString(),
  alert_id: alert.id || 'unknown',
